import { runMach } from './mach.js';
import { prepareProject } from './prepare.js';
import { loadBrowserConfig } from './config/load.js';
export async function runWorkflow(workflow, args = [], cwd = process.cwd()) {
    if (workflow === 'bootstrap') {
        return runMach(['bootstrap', ...args], cwd);
    }
    if (workflow === 'package' && (await loadBrowserConfig(cwd)).build.mode !== 'full') {
        throw new Error('Release packages require full build mode. Set build.mode to "full" and run setup again.');
    }
    await prepareProject(cwd);
    if (workflow === 'apply')
        return 0;
    if (workflow === 'package') {
        const buildCode = await runMach(['build'], cwd);
        return buildCode === 0 ? runMach(['package', ...args], cwd) : buildCode;
    }
    return runMach([workflow, ...args], cwd);
}
